/// <summary>
/// SysOperation service class to update ETGSPAIN model fields in packing slips.
/// </summary>
internal final class ETGSPAINSalesPackingSlipUpdateETGSPAINExtraFieldsService extends SysOperationServiceBase
{
}

Method.Source:
    /// <summary>
    /// Main method executing the <c>SysOperation</c> to update the fields.
    /// </summary>
    /// <param name = "_contract">Contract containing the required parameters.</param>
    public void process(ETGSPAINSalesPackingSlipUpdateETGSPAINExtraFieldsContract _contract)
    {
        CustPackingSlipTrans            custPackingSlipTrans            = _contract.parmCallerBuffer();

        ETGSPAINInventLicensePlate           ETGSPAINInventLicensePlate           = _contract.parmETGSPAINInventLicensePlate();
        ETGSPAINSalesCustomerWithdrawalDate  ETGSPAINSalesCustomerWithdrawalDate  = _contract.parmETGSPAINSalesCustomerWithdrawalDate();
        ETGSPAINCustSalesReference           ETGSPAINCustSalesReference           = _contract.parmETGSPAINCustSalesReference();
        ETGSPAINInventPackingSlipTransitId   ETGSPAINInventPackingSlipTransitId   = _contract.parmETGSPAINInventPackingSlipTransitId();

        CustPackingSlipTrans            custPackingSlipTransUpdate;      

        update_recordset custPackingSlipTransUpdate
            setting ETGSPAINInventLicensePlate       = ETGSPAINInventLicensePlate,
                ETGSPAINSalesCustomerWithdrawalDate  = ETGSPAINSalesCustomerWithdrawalDate,
                ETGSPAINCustSalesReference           = ETGSPAINCustSalesReference,
                ETGSPAINInventPackingSlipTransitId   = ETGSPAINInventPackingSlipTransitId
            where custPackingSlipTransUpdate.RecId == custPackingSlipTrans.RecId;        
	}
